Refactor this legacy component to Angular 21 modern style. The component is in libs/common/src/lib/knowledge-box-settings/ and currently uses constructor injection, @Input()/@Output() decorators, and a takeUntil(Subject) cleanup pattern. Here's the current code:

@Component({
  selector: 'stf-kb-settings',
  templateUrl: './knowledge-box-settings.component.html',
  styleUrls: ['./knowledge-box-settings.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
  standalone: false,
})
export class KnowledgeBoxSettingsComponent implements OnInit, OnDestroy {
  @Input() kbSlug: string = '';
  @Input() readonly: boolean = false;
  @Output() saved = new EventEmitter<void>();

  private unsubscribeAll = new Subject<void>();
  saving = false;

  constructor(
    private sdk: SDKService,
    private toast: SisToastService,
    private cdr: ChangeDetectorRef,
  ) {}

  ngOnInit() {
    this.sdk.currentKb
      .pipe(takeUntil(this.unsubscribeAll))
      .subscribe((kb) => { this.cdr.markForCheck(); });
  }

  ngOnDestroy() {
    this.unsubscribeAll.next();
    this.unsubscribeAll.complete();
  }

  save() {
    this.saving = true;
    this.sdk.currentKb.pipe(take(1), switchMap(kb => kb.modify({ slug: this.kbSlug }))).subscribe({
      next: () => { this.saving = false; this.saved.emit(); },
      error: () => { this.saving = false; this.toast.error('Failed'); this.cdr.markForCheck(); },
    });
  }
}
